        vector<int> res;
        if (n == 1) {
            for (int i = 0; i <= 9; ++i) {
                res.push_back(i);
            }
            return res;
        }
        for (int i = 1; i <= 9; ++i) {
            int num = i;
            int prev = i;
            for (int j = 1; j < n; ++j) {
                int next = (prev - k + 10) % 10;
                if (next == prev) next = (prev + k) % 10;
                num = num * 10 + next;
                prev = next;
            }
            res.push_back(num);
            if (k != 0) {
                num = i;
                prev = i;
                for (int j = 1; j < n; ++j) {
                    next = (prev + k) % 10;
                    num = num * 10 + next;
                    prev = next;
                }
                res.push_back(num);
            }
        }
        return res;
    }
